package com.vidaysalud.veterinaria.recetaservicio.model;import jakarta.persistence.*;import lombok.*;import java.time.LocalDateTime;import java.util.*;@Entity @Table(name="receta") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class Receta{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="id_receta")private Integer idReceta;@Column(name="id_consulta",nullable=false)private Integer idConsulta;@Column(name="fecha_emision",nullable=false,updatable=false)private LocalDateTime fechaEmision;@Lob @Column(name="indicaciones_generales")private String indicacionesGenerales;@OneToMany(mappedBy="receta",cascade=CascadeType.ALL,orphanRemoval=true,fetch=FetchType.LAZY)@Builder.Default private List<DetalleReceta> detalles=new ArrayList<>();@PrePersist void pre(){if(fechaEmision==null)fechaEmision=LocalDateTime.now();}public void agregarDetalle(DetalleReceta d){d.setReceta(this);detalles.add(d);}}